class Solution:
    def minimumOperationsToMakeEqual(self, x, y):
        # Independent Dijkstra (priority queue) over the same move set; if the
        # BFS implementation has an off-by-one in its bound or neighbor list,
        # this differently-structured search will disagree.
        import heapq
        if x == y:
            return 0
        upper = max(x, y) + 1000
        dist = {x: 0}
        pq = [(0, x)]
        while pq:
            d, v = heapq.heappop(pq)
            if v == y:
                return d
            if d > dist.get(v, float('inf')):
                continue
            nbrs = []
            if v % 11 == 0:
                nbrs.append(v // 11)
            if v % 5 == 0:
                nbrs.append(v // 5)
            if v + 1 <= upper:
                nbrs.append(v + 1)
            if v - 1 >= 0:
                nbrs.append(v - 1)
            for nv in nbrs:
                nd = d + 1
                if nd < dist.get(nv, float('inf')):
                    dist[nv] = nd
                    heapq.heappush(pq, (nd, nv))
        return dist[y]

