from collections import deque

class Solution:
    def minimumOperationsToMakeEqual(self, x, y):
        if x == y:
            return 0
        upper = max(x, y) + 1000
        dist = [-1] * (upper + 1)
        dist[x] = 0
        dq = deque([x])
        while dq:
            v = dq.popleft()
            if v == y:
                return dist[v]
            nbrs = []
            if v % 11 == 0:
                nbrs.append(v // 11)
            if v % 5 == 0:
                nbrs.append(v // 5)
            if v + 1 <= upper:
                nbrs.append(v + 1)
            if v - 1 >= 0:
                nbrs.append(v - 1)
            for nv in nbrs:
                if 0 <= nv <= upper and dist[nv] == -1:
                    dist[nv] = dist[v] + 1
                    dq.append(nv)
        return dist[y]

