var minimumOperationsToMakeEqual = function(x, y) {
    if (x === y) return 0;
    const upper = Math.max(x, y) + 1000;
    const dist = new Array(upper + 1).fill(-1);
    dist[x] = 0;
    const dq = [x];
    let head = 0;
    while (head < dq.length) {
        const v = dq[head++];
        if (v === y) return dist[v];
        const nbrs = [];
        if (v % 11 === 0) nbrs.push(v / 11);
        if (v % 5 === 0) nbrs.push(v / 5);
        if (v + 1 <= upper) nbrs.push(v + 1);
        if (v - 1 >= 0) nbrs.push(v - 1);
        for (const nv of nbrs) {
            if (nv >= 0 && nv <= upper && dist[nv] === -1) {
                dist[nv] = dist[v] + 1;
                dq.push(nv);
            }
        }
    }
    return dist[y];
};
